sql:
SELECT UPPER(control_feature_name) AS "Control Feature"
FROM control_features
WHERE description = 'Start or stop recording video';

SELECT weight
FROM gimbals
WHERE gimbal_model = 'Ronin-S';

SELECT AVG(weight) 
FROM gimbals 
WHERE firmware_version = 'v1.0';

